import "fmt"

type Book struct {
	Title         string
	IsCheckedOut  bool
}

func (b Book) Describe() {
	status := "available"
	if b.IsCheckedOut {
		status = "checked out"
	}
	fmt.Printf("%s is %s\n", b.Title, status)
}

func (b *Book) CheckOut() {
	b.IsCheckedOut = true
}

func main() {
	b := Book{Title: "The Hobbit"}
	b.Describe()
	b.CheckOut()
	b.Describe()
}

